import { useEffect, useState } from 'react';
import { useQuery, useMutation } from 'convex/react';
import { api } from '../../convex/_generated/api';
import { useNavigate } from 'react-router-dom';
import { PhoneCall, Phone, PhoneOff, Package } from 'lucide-react';

export default function GlobalCallListener() {
  const calls = useQuery(api.calls.getActiveCalls) || [];
  const rejectCall = useMutation(api.calls.rejectCall);
  const navigate = useNavigate();
  const [notified, setNotified] = useState(new Set());

  // Find if there is any ringing user call we need to show
  const ringingCall = calls.find(c => c.status === 'ringing' && c.caller === 'user');

  const shipment = useQuery(
    api.shipments.getByTracking,
    ringingCall?.trackingNumber ? { trackingNumber: ringingCall.trackingNumber } : 'skip'
  );

  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted' && Notification.permission !== 'denied') {
      Notification.requestPermission();
    }
  }, []);

  useEffect(() => {
    if (ringingCall) {
      if (!notified.has(ringingCall._id)) {
         if ('Notification' in window && Notification.permission === 'granted') {
           new Notification('Incoming Call', {
             body: `Incoming support call from ${ringingCall.trackingNumber ? `Shipment #${ringingCall.trackingNumber}` : 'Guest User'}`,
           });
         }
         setNotified(prev => new Set(prev).add(ringingCall._id));
      }
    }
  }, [ringingCall, notified]);

  if (!ringingCall) return null;

  return (
    <div style={{
      position: 'fixed', bottom: 24, left: 24, zIndex: 99999, 
      background: 'var(--clr-navy-900)', border: '1px solid hsla(40,95%,52%,0.3)',
      borderRadius: 'var(--radius-xl)', padding: 24, boxShadow: '0 10px 40px rgba(0,0,0,0.5)',
      width: 320, display: 'flex', flexDirection: 'column', gap: 16
    }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
         <div className="pulse-dot pulse-dot-gold" style={{ width: 48, height: 48, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <PhoneCall size={20} color="var(--clr-navy-950)" />
         </div>
         <div>
            <div style={{ fontWeight: 600, color: '#fff', fontSize: '1.1rem' }}>Incoming Call</div>
            <div className="text-xs" style={{ color: 'var(--clr-gold-400)' }}>
              {ringingCall.trackingNumber ? `Shipment #${ringingCall.trackingNumber}` : 'Guest User'}
            </div>
         </div>
      </div>

      {shipment && (
        <div style={{ background: 'hsla(0,0%,100%,0.05)', borderRadius: 8, padding: 12, fontSize: '0.85rem' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6, color: 'var(--clr-slate-300)', marginBottom: 8 }}>
            <Package size={14} /> {shipment.packageType} ({shipment.weight}{shipment.weightUnit})
          </div>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 8 }}>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div className="text-xs" style={{ color: 'var(--clr-slate-500)', marginBottom: 2 }}>From</div>
              <div style={{ color: 'var(--clr-white)', fontWeight: 500, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{shipment.senderName}</div>
            </div>
            <div style={{ color: 'var(--clr-gold-500)', flexShrink: 0 }}>→</div>
            <div style={{ flex: 1, textAlign: 'right', minWidth: 0 }}>
              <div className="text-xs" style={{ color: 'var(--clr-slate-500)', marginBottom: 2 }}>To</div>
              <div style={{ color: 'var(--clr-white)', fontWeight: 500, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{shipment.receiverName}</div>
            </div>
          </div>
        </div>
      )}

      <div style={{ display: 'flex', gap: 8 }}>
        <button className="btn btn-primary" onClick={() => navigate('/admin/live')} style={{ flex: 1, padding: '8px 12px' }}>
           <Phone size={14} /> Answer
        </button>
        <button className="btn btn-danger" onClick={() => rejectCall({ callId: ringingCall._id })} style={{ flex: 1, padding: '8px 12px' }}>
           <PhoneOff size={14} /> Reject
        </button>
      </div>
    </div>
  );
}

