import { useState, useEffect, useRef } from 'react';
import { useQuery, useMutation } from 'convex/react';
import { api } from '../../convex/_generated/api';
import { useLocation } from 'react-router-dom';
import { MessageSquare, Phone, X, Send, Minimize2, Check, Clock, AlertTriangle, PhoneCall, PhoneOff } from 'lucide-react';
import { format } from 'date-fns';
import './LiveWidget.css';

// Generate or get stable fingerprint
const getFingerprint = () => {
  let fp = localStorage.getItem('shipmate_fp');
  if (!fp) {
    fp = Math.random().toString(36).substring(2) + Date.now().toString(36);
    localStorage.setItem('shipmate_fp', fp);
  }
  return fp;
};

export default function LiveWidget() {
  const [isOpen, setIsOpen] = useState(false);
  const [tab, setTab] = useState('chat'); // 'chat' or 'call'
  const [minimized, setMinimized] = useState(false);
  const { pathname } = useLocation();
  const fingerprint = getFingerprint();

  const activeCall = useQuery(api.calls.getActiveCallForFingerprint, { fingerprint });

  useEffect(() => {
    if (activeCall?.status === 'ringing' && activeCall?.caller === 'admin') {
      setIsOpen(true);
      setTab('call');
      setMinimized(false);
    }
  }, [activeCall?.status, activeCall?.caller]);

  // Heartbeat
  const sendHeartbeat = useMutation(api.online.heartbeat);
  useEffect(() => {
    if ('Notification' in window && Notification.permission !== 'granted' && Notification.permission !== 'denied') {
      Notification.requestPermission();
    }
    const region = Intl.DateTimeFormat().resolvedOptions().timeZone;
    sendHeartbeat({ fingerprint, path: pathname, region });
    const int = setInterval(() => sendHeartbeat({ fingerprint, path: pathname, region }), 30000);
    return () => clearInterval(int);
  }, [pathname]);

  return (
    <>
      <div className={`live-widget ${isOpen ? 'open' : ''}`}>
        {!isOpen && (
          <div className="widget-triggers">
            <button 
              className="widget-trigger call-trigger"
              onClick={() => { setTab('call'); setIsOpen(true); }}
              aria-label="Open Call Support"
            >
              <PhoneCall size={24} />
            </button>
            <button 
              className="widget-trigger chat-trigger"
              onClick={() => { setTab('chat'); setIsOpen(true); }}
              aria-label="Open Live Chat"
            >
              <MessageSquare size={24} />
            </button>
          </div>
        )}

        {isOpen && (
          <div className="widget-panel glass">
            <div className="widget-header">
              <div style={{ display: 'flex', gap: 16 }}>
                <button className={`widget-tab ${tab === 'chat' ? 'active' : ''}`} onClick={() => setTab('chat')}>
                  <MessageSquare size={16} /> Chat
                </button>
                <button className={`widget-tab ${tab === 'call' ? 'active' : ''}`} onClick={() => setTab('call')}>
                  <Phone size={16} /> Live Call
                </button>
              </div>
              <div style={{ display: 'flex', gap: 8 }}>
                <button className="widget-action" onClick={() => setMinimized(!minimized)}>
                  <Minimize2 size={16} />
                </button>
                <button className="widget-action" onClick={() => setIsOpen(false)}>
                  <X size={16} />
                </button>
              </div>
            </div>

            <div className="widget-body" style={{ display: minimized ? 'none' : 'flex' }}>
              {tab === 'chat' ? <ChatTab fingerprint={fingerprint} /> : <CallTab fingerprint={fingerprint} activeCall={activeCall} />}
            </div>
          </div>
        )}
      </div>
      {isOpen && <div className="widget-mobile-overlay" onClick={() => setIsOpen(false)} />}
    </>
  );
}

function ChatTab({ fingerprint }) {
  const session = useQuery(api.chat.getSession, { fingerprint });
  const startSession = useMutation(api.chat.startSession);
  const sendMessage = useMutation(api.chat.sendMessage);
  const messages = useQuery(api.chat.getMessages, { sessionId: session?._id }) || [];

  const [text, setText] = useState('');
  const [name, setName] = useState('');
  const scrollRef = useRef();

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleStart = async (e) => {
    e.preventDefault();
    if (!name.trim()) return;
    await startSession({ fingerprint, userName: name });
  };

  const handleSend = async (e) => {
    e.preventDefault();
    if (!text.trim() || !session) return;
    await sendMessage({ sessionId: session._id, sender: 'user', text });
    setText('');
  };

  if (!session) {
    return (
      <form onSubmit={handleStart} className="widget-start">
        <h3 className="text-h3" style={{ fontSize: '1.2rem', marginBottom: 8 }}>Welcome to ShipMate</h3>
        <p className="text-sm" style={{ marginBottom: 20 }}>Please enter your name to start chatting with our logistics experts.</p>
        <input className="form-input" placeholder="Your Name" value={name} onChange={e=>setName(e.target.value)} required />
        <button className="btn btn-primary" type="submit" style={{ width: '100%', marginTop: 12 }}>Start Chat</button>
      </form>
    );
  }

  return (
    <div className="chat-container">
      <div className="chat-messages" ref={scrollRef}>
        {messages.length === 0 && (
          <div style={{ textAlign: 'center', opacity: 0.5, marginTop: 40, fontSize: '0.8rem' }}>
            Say hello to a ShipMate representative!
          </div>
        )}
        {messages.map(m => (
          <div key={m._id} className={`chat-bubble ${m.sender === 'user' ? 'outgoing' : 'incoming'}`}>
            <div className="chat-text">{m.text}</div>
            <div className="chat-time">{format(new Date(m.createdAt), 'HH:mm')}</div>
          </div>
        ))}
      </div>
      <form className="chat-input-area" onSubmit={handleSend}>
        <input className="form-input" style={{ borderRadius: 'var(--radius-full)' }} placeholder="Type a message..." value={text} onChange={e=>setText(e.target.value)} />
        <button type="submit" className="chat-send-btn" disabled={!text.trim()}><Send size={15} /></button>
      </form>
    </div>
  );
}

function CallTab({ fingerprint, activeCall }) {
  const initiateCall = useMutation(api.calls.initiateCall);
  const answerCall = useMutation(api.calls.answerCall);
  const endCall = useMutation(api.calls.endCall);
  const rejectCall = useMutation(api.calls.rejectCall);
  const addSignal = useMutation(api.calls.addSignal);
  const signals = useQuery(api.calls.getSignals, { callId: activeCall?._id }) || [];
  const waitTime = useQuery(api.calls.getUserWaitTime) || 0;
  const isAdminBusy = useQuery(api.calls.isAdminBusy) || false;

  const shipment = useQuery(api.shipments.getByTracking, activeCall?.trackingNumber ? { trackingNumber: activeCall.trackingNumber } : 'skip');

  const [trackingNumber, setTrackingNumber] = useState('');
  const [error, setError] = useState('');
  const pcRef = useRef(null);
  const audioRef = useRef(null);

  // WebRTC Setup
  useEffect(() => {
    if (activeCall?.status === 'connected' && !pcRef.current) {
      setupWebRTC();
    }
  }, [activeCall?.status]);

  // Handle incoming signals from admin
  useEffect(() => {
    if (!pcRef.current || !activeCall) return;
    const processSignals = async () => {
      const adminSignals = signals.filter(s => s.sender === 'admin');
      for (const sig of adminSignals) {
        try {
          const data = JSON.parse(sig.data);
          if (sig.type === 'offer') {
            await pcRef.current.setRemoteDescription(data);
            const answer = await pcRef.current.createAnswer();
            await pcRef.current.setLocalDescription(answer);
            await addSignal({ callId: activeCall._id, sender: 'user', type: 'answer', data: JSON.stringify(answer) });
          } else if (sig.type === 'answer' && pcRef.current.signalingState !== 'stable') {
            await pcRef.current.setRemoteDescription(data);
          } else if (sig.type === 'ice-candidate') {
            await pcRef.current.addIceCandidate(data);
          }
        } catch(e) { console.warn('Signal process error', e); }
      }
    };
    processSignals();
  }, [signals.length]);

  const setupWebRTC = async () => {
    try {
      const pc = new RTCPeerConnection({ iceServers: [{ urls: 'stun:stun.l.google.com:19302' }] });
      pcRef.current = pc;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      stream.getTracks().forEach(t => pc.addTrack(t, stream));

      pc.ontrack = e => {
        if (!audioRef.current) {
          const a = new Audio();
          a.autoplay = true;
          a.srcObject = e.streams[0];
          audioRef.current = a;
        }
      };

      pc.onicecandidate = e => {
        if (e.candidate) {
          addSignal({ callId: activeCall._id, sender: 'user', type: 'ice-candidate', data: JSON.stringify(e.candidate) });
        }
      };

      const offer = await pc.createOffer();
      await pc.setLocalDescription(offer);
      await addSignal({ callId: activeCall._id, sender: 'user', type: 'offer', data: JSON.stringify(offer) });

    } catch (err) {
      console.warn('WebRTC Setup Error', err);
      setError('Microphone access is required to place a call.');
    }
  };

  const handleCall = async (e) => {
    e.preventDefault();
    setError('');
    const t = trackingNumber.trim();
    if (!t) { setError('Tracking number required for support call.'); return; }
    try {
      await initiateCall({ fingerprint, caller: 'user', trackingNumber: t });
    } catch (err) {
      setError(err.message || 'Call failed');
    }
  };

  const handleAnswer = async () => {
    setError('');
    try {
      if (!pcRef.current) await setupWebRTC();
      await answerCall({ callId: activeCall._id });
    } catch(err) {
      console.warn('Answer error', err);
      setError('Could not access microphone');
    }
  };

  const handleHangup = async () => {
    if (pcRef.current) pcRef.current.close();
    pcRef.current = null;
    if (audioRef.current) { audioRef.current.pause(); audioRef.current = null; }
    if (activeCall) await endCall({ callId: activeCall._id });
  };

  if (!activeCall || activeCall.status === 'ended' || activeCall.status === 'missed') {
    return (
      <form onSubmit={handleCall} className="widget-start">
        <h3 className="text-h3" style={{ fontSize: '1.2rem', marginBottom: 8 }}>Live Voice Support</h3>
        <p className="text-sm" style={{ marginBottom: 20 }}>Please provide your Tracking Number or Email to verify your shipment and speak with an agent.</p>
        <input className="form-input" placeholder="Tracking Number or Email" value={trackingNumber} onChange={e=>setTrackingNumber(e.target.value)} required />
        {error && <div className="form-error" style={{ marginTop: 10 }}>{error}</div>}
        <button className="btn btn-teal" type="submit" style={{ width: '100%', marginTop: 12 }}>
          <PhoneCall size={15} /> Call Agent
        </button>
      </form>
    );
  }

  return (
    <div className="call-container" style={{ textAlign: 'center', paddingTop: 40 }}>
      {activeCall.status === 'ringing' && activeCall.caller === 'user' && !isAdminBusy && (
        <>
          <div className="pulse-dot pulse-dot-gold" style={{ width: 64, height: 64, margin: '0 auto 20px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Phone size={24} color="var(--clr-navy-950)" />
          </div>
          <h3 className="text-h3" style={{ marginBottom: 8 }}>Calling Agent...</h3>
          <p className="text-sm">Please wait while we connect you.</p>
        </>
      )}

      {activeCall.status === 'ringing' && activeCall.caller === 'user' && isAdminBusy && (
        <>
          <div className="pulse-dot pulse-dot-warning" style={{ width: 64, height: 64, margin: '0 auto 20px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'var(--clr-warning)', boxShadow: '0 0 15px hsla(35,100%,50%,0.5)' }}>
            <Clock size={24} color="var(--clr-navy-950)" />
          </div>
          <h3 className="text-h3" style={{ marginBottom: 8 }}>Waiting for Agent</h3>
          <p className="text-sm">Estimated wait time: {waitTime} mins</p>
          <div className="shimmer" style={{ width: 120, height: 4, borderRadius: 2, background: 'hsla(0,0%,100%,0.1)', margin: '20px auto' }} />
        </>
      )}

      {activeCall.status === 'ringing' && activeCall.caller === 'admin' && (
        <>
          <div className="pulse-dot pulse-dot-gold" style={{ width: 64, height: 64, margin: '0 auto 20px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <PhoneCall size={24} color="var(--clr-navy-950)" />
          </div>
          <h3 className="text-h3" style={{ marginBottom: 8 }}>Incoming Call</h3>
          <p className="text-sm">A ShipMate agent is calling you.</p>
          {error && <div className="form-error" style={{ marginTop: 10 }}>{error}</div>}
          <div style={{ display: 'flex', gap: 10, marginTop: 24 }}>
             <button className="btn btn-primary" onClick={handleAnswer} style={{ flex: 1 }}><Phone size={15} /> Answer</button>
             <button className="btn btn-danger" onClick={() => rejectCall({ callId: activeCall._id})} style={{ flex: 1 }}><PhoneOff size={15} /> Decline</button>
          </div>
        </>
      )}

      {(activeCall.status === 'connected' || (activeCall.status === 'ringing' && activeCall.caller === 'admin')) && shipment && (
        <div style={{ textAlign: 'left', background: 'hsla(0,0%,100%,0.05)', padding: '16px', borderRadius: 12, marginTop: 24, border: '1px solid hsla(0,0%,100%,0.1)' }}>
          <p className="text-xs" style={{ color: 'var(--clr-gold-400)', marginBottom: 6, fontWeight: 600 }}>SHIPMENT #{shipment.trackingNumber}</p>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 12, fontSize: '0.85rem' }}>
            <div style={{ flex: 1 }}><div className="text-xs" style={{ color: 'var(--clr-slate-400)', marginBottom: 2 }}>From</div><div style={{ color: 'var(--clr-white)', fontWeight: 500 }}>{shipment.senderName}</div></div>
            <div style={{ color: 'var(--clr-gold-500)' }}>→</div>
            <div style={{ flex: 1, textAlign: 'right' }}><div className="text-xs" style={{ color: 'var(--clr-slate-400)', marginBottom: 2 }}>To</div><div style={{ color: 'var(--clr-white)', fontWeight: 500 }}>{shipment.receiverName}</div></div>
          </div>
        </div>
      )}

      {activeCall.status === 'busy' && (
        <>
          <AlertTriangle size={48} color="var(--clr-warning)" style={{ margin: '0 auto 20px' }} />
          <h3 className="text-h3" style={{ marginBottom: 8 }}>Agents are Busy</h3>
          <p className="text-sm">All our agents are currently on another line. Please try again later or use the chat tab.</p>
        </>
      )}

      {activeCall.status === 'connected' && (
        <>
          <div className="pulse-dot pulse-dot-green" style={{ width: 64, height: 64, margin: '0 auto 20px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Clock size={24} color="#fff" />
          </div>
          <h3 className="text-h3" style={{ marginBottom: 8 }}>Call Connected</h3>
          <p className="text-sm" style={{ color: 'var(--clr-teal-400)' }}>Secure WebRTC Channel</p>
        </>
      )}

      {!(activeCall.status === 'ringing' && activeCall.caller === 'admin') && (
        <button className="btn btn-danger" onClick={handleHangup} style={{ marginTop: 40, width: '100%' }}>
          <PhoneOff size={15} /> {activeCall.status === 'ringing' ? 'Cancel Call' : 'End Call'}
        </button>
      )}
    </div>
  );
}
